pub struct Note {
    pub title: String,
    pub body: String,
    pub pinned: bool,
}

use note_method_lab::Note;

#[test]
fn summarizes_note_body_length() {
    let note = Note {
        title: String::from("Rust notes"),
        body: String::from("Cargo"),
        pinned: false,
    };

    assert_eq!(note.summary(), "Rust notes: 5 characters");
}
